const jobTitles = [
  'Data Analyst',
  'People Analyst',
  'BI Analyst',
  'Tableau Specialist',
  'Business Analyst',
  'Financial Analyst'
];

const queries = jobTitles.map(title => ({
  json: {
    jobTitle: title,
    minSalary: 20000,
    willingToRelocate: true
  }
}));

return queries;

const apiKey = $env.SERPAPI_KEY;
const jobTitle = $json.jobTitle;
const maxPages = 3;
let allResults = [];
let nextPageToken = null;

for (let page = 0; page < maxPages; page++) {
  let url = `https://serpapi.com/search.json?engine=google_jobs&q=${encodeURIComponent(jobTitle)}&api_key=${apiKey}&num=10&location=United+States`;

  if (nextPageToken) {
    url += `&next_page_token=${encodeURIComponent(nextPageToken)}`;
  }

  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    json: true
  });

  if (response.jobs_results && response.jobs_results.length > 0) {
    allResults = allResults.concat(response.jobs_results);
  }

  if (response.serpapi_pagination && response.serpapi_pagination.next_page_token) {
    nextPageToken = response.serpapi_pagination.next_page_token;
  } else {
    break;
  }
}

return [{ json: { jobs_results: allResults, _searchedTitle: jobTitle } }];

const allJobs = [];
const seen = new Set();

for (const item of $input.all()) {
  const data = item.json;

  // Parse Google Jobs (SerpAPI)
  if (data.jobs_results && Array.isArray(data.jobs_results)) {
    for (const job of data.jobs_results) {
      const key = `${job.title}-${job.company_name}`.toLowerCase();
      if (!seen.has(key)) {
        seen.add(key);
        allJobs.push({
          json: {
            Source: 'Google Jobs',
            Title: job.title || '',
            Company: job.company_name || '',
            Location: job.location || '',
            Salary: job.detected_extensions?.salary || 'Not Listed',
            PostedDate: job.detected_extensions?.posted_at || '',
            Description: (job.description || '').substring(0, 300),
            ApplyLink: job.apply_options?.[0]?.link || job.share_link || '',
            JobType: job.detected_extensions?.schedule_type || '',
            SearchedTitle: data._searchedTitle || ''
          }
        });
      }
    }
  }

  // Parse Adzuna
  if (data.results && Array.isArray(data.results)) {
    for (const job of data.results) {
      const key = `${job.title}-${job.company?.display_name}`.toLowerCase();
      if (!seen.has(key)) {
        seen.add(key);
        allJobs.push({
          json: {
            Source: 'Adzuna',
            Title: job.title || '',
            Company: job.company?.display_name || '',
            Location: job.location?.display_name || '',
            Salary: job.salary_is_predicted === '1' ? `~$${Math.round(job.salary_min || 0)}–$${Math.round(job.salary_max || 0)}` : (job.salary_min ? `$${Math.round(job.salary_min)}–$${Math.round(job.salary_max)}` : 'Not Listed'),
            PostedDate: job.created || '',
            Description: (job.description || '').substring(0, 300),
            ApplyLink: job.redirect_url || '',
            JobType: job.contract_time || '',
            SearchedTitle: data._searchedTitle || ''
          }
        });
      }
    }
  }

  // Parse Remotive
  if (data.jobs && Array.isArray(data.jobs)) {
    for (const job of data.jobs) {
      const key = `${job.title}-${job.company_name}`.toLowerCase();
      if (!seen.has(key)) {
        seen.add(key);
        allJobs.push({
          json: {
            Source: 'Remotive',
            Title: job.title || '',
            Company: job.company_name || '',
            Location: job.candidate_required_location || 'Remote',
            Salary: job.salary || 'Not Listed',
            PostedDate: job.publication_date || '',
            Description: (job.description || '').replace(/<[^>]*>/g, '').substring(0, 300),
            ApplyLink: job.url || '',
            JobType: job.job_type || '',
            SearchedTitle: job.category || ''
          }
        });
      }
    }
  }
}

if (allJobs.length === 0) {
  return [{ json: { Source: 'None', Title: 'No jobs found', Company: '', Location: '', Salary: '', PostedDate: '', Description: '', ApplyLink: '', JobType: '', SearchedTitle: '' } }];
}

return allJobs;

const skills = [
  'data analyst', 'people analyst', 'bi analyst', 'tableau',
  'business analyst', 'financial analyst', 'sql', 'excel',
  'power bi', 'python', 'dashboard', 'data visualization',
  'eda', 'reporting', 'pivot table', 'vlookup', 'kpi',
  'data cleaning', 'etl', 'google sheets', 'pandas'
];

const results = [];

for (const item of $input.all()) {
  const job = item.json;
  const text = `${job.Title} ${job.Description} ${job.JobType}`.toLowerCase();

  let matchCount = 0;
  const matchedSkills = [];

  for (const skill of skills) {
    if (text.includes(skill)) {
      matchCount++;
      matchedSkills.push(skill);
    }
  }

  // Keep jobs with at least 1 skill match
  if (matchCount >= 1) {
    results.push({
      json: {
        ...job,
        SkillMatchCount: matchCount,
        MatchedSkills: matchedSkills.join(', '),
        RelevanceScore: Math.round((matchCount / skills.length) * 100) + '%'
      }
    });
  }
}

// Sort by relevance (highest match count first)
results.sort((a, b) => b.json.SkillMatchCount - a.json.SkillMatchCount);

if (results.length === 0) {
  return [{ json: { Source: 'None', Title: 'No matching jobs found', Company: '', Location: '', Salary: '', PostedDate: '', Description: '', ApplyLink: '', JobType: '', SkillMatchCount: 0, MatchedSkills: '', RelevanceScore: '0%' } }];
}

return results;

const now = new Date().toISOString().split('T')[0];
const rows = [];

for (const item of $input.all()) {
  const j = item.json;
  rows.push({
    json: {
      DateFound: now,
      Source: j.Source,
      JobTitle: j.Title,
      Company: j.Company,
      Location: j.Location,
      Salary: j.Salary,
      PostedDate: j.PostedDate,
      JobType: j.JobType,
      RelevanceScore: j.RelevanceScore,
      MatchedSkills: j.MatchedSkills,
      ApplyLink: j.ApplyLink,
      Description: j.Description,
      Applied: 'No'
    }
  });
}

return rows;

// Get new jobs from Format node (input 0)
const newJobs = $input.all();

// Get existing jobs from Read Existing Jobs node
let existingJobs = [];
try {
  existingJobs = $('Read Existing Jobs').all();
} catch (e) {
  // Sheet is empty, no existing jobs
  existingJobs = [];
}

// Build a Set of existing job keys (JobTitle + Company) for fast lookup
const existingKeys = new Set();
for (const existing of existingJobs) {
  const title = (existing.json.JobTitle || '').toLowerCase().trim();
  const company = (existing.json.Company || '').toLowerCase().trim();
  if (title) {
    existingKeys.add(`${title}|||${company}`);
  }
}

// Filter out jobs that already exist in the sheet
const onlyNewJobs = [];
for (const job of newJobs) {
  const title = (job.json.JobTitle || '').toLowerCase().trim();
  const company = (job.json.Company || '').toLowerCase().trim();
  const key = `${title}|||${company}`;

  if (!existingKeys.has(key)) {
    onlyNewJobs.push(job);
  }
}

if (onlyNewJobs.length === 0) {
  return [{ json: { _noNewJobs: true, message: 'No new jobs found. All jobs already exist in sheet.' } }];
}

return onlyNewJobs;

const count = $input.all().length;
return [{
  json: {
    summary: `Job search completed! Added ${count} NEW jobs to Google Sheets.`,
    newJobCount: count,
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    summary: 'Job search completed. No new jobs found — all results already exist in your sheet.',
    newJobCount: 0,
    timestamp: new Date().toISOString()
  }
}];
